-- Biblioteca compartilhada de exercicios (reaproveitada do Fox Performance).
-- Somente leitura para profissionais/alunos autenticados; escrita restrita ao SQL Editor.

create table if not exists exercise_library (
  id serial primary key,
  exercise_id integer unique not null,
  nome text not null,
  gif_url text,
  grupo_muscular text,
  categoria text,
  exercise_ref text
);

alter table exercise_library enable row level security;

create policy "authenticated users read exercise library"
  on exercise_library for select
  to authenticated
  using (true);

on conflict (exercise_id) do nothing;
